import { useNavigate, useLocation } from 'react-router-dom'
import { useState } from 'react'

interface LayoutProps {
  children: React.ReactNode
  showNovaNF?: boolean
  onNovaNF?: () => void
}

const ENOVA_LOGO = "data:image/png;base64,"

export default function Layout({ children, showNovaNF, onNovaNF }: LayoutProps) {
  const navigate = useNavigate()
  const location = useLocation()
  const [empresa, setEmpresa] = useState<'six' | 'enova'>('six')
  const isSix = empresa === 'six'

  const now = new Date()
  const meses = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez']
  const mesAtual = meses[now.getMonth()]
  const anoAtual = now.getFullYear()

  const pageLabels: Record<string, string> = {
    '/dashboard': 'Painel',
    '/inicio': 'Início',
    '/faturamentos': 'Faturamentos',
    '/impostos': 'Impostos Pagos',
    '/empresas': 'Empresas',
    '/usuarios': 'Usuários',
    '/configuracoes': 'Configurações',
    '/encargos': 'Encargos',
    '/xml': 'Importar XML',
    '/exportar': 'Exportar Excel',
    '/contabilidade': 'Contabilidade',
    '/relatorios': 'Relatórios',
  }

  const paginasGlobais = ['/dashboard', '/inicio', '/empresas', '/usuarios']
  const paginaAtual = pageLabels[location.pathname] || 'Controle Fiscal'
  const nomePagina = paginasGlobais.includes(location.pathname)
    ? paginaAtual
    : paginaAtual

  const nomeEmpresaCompleto = isSix
    ? 'SIX Comercial Artigos Promocionais'
    : 'ENOVA Comercial Artigos Promocionais'

  function logout() {
    localStorage.removeItem('access_token')
    localStorage.removeItem('usuario')
    navigate('/login')
  }

  function NavItem({ path, icon, label, badge, cor }: {
    path: string; icon: string; label: string; badge?: number; cor?: 'purple'
  }) {
    const ativo = location.pathname === path
    let bgAtivo = isSix ? '#1C2E52' : '#0D3326'
    let corAtivo = isSix ? '#4F8EF7' : '#34D399'
    if (cor === 'purple') { bgAtivo = '#2A1A52'; corAtivo = '#A78BFA' }

    return (
      <div
        onClick={() => navigate(path)}
        style={{
          display: 'flex', alignItems: 'center', gap: '9px',
          padding: '8px 10px', borderRadius: '6px', cursor: 'pointer',
          color: ativo ? corAtivo : '#7B82A0',
          background: ativo ? bgAtivo : 'transparent',
          fontSize: '13px', fontWeight: 500,
          transition: 'all .15s', marginBottom: '2px',
        }}
        onMouseEnter={e => { if (!ativo) { const el = e.currentTarget as HTMLDivElement; el.style.background = '#1A1D2A'; el.style.color = '#E8EAF0' } }}
        onMouseLeave={e => { if (!ativo) { const el = e.currentTarget as HTMLDivElement; el.style.background = 'transparent'; el.style.color = '#7B82A0' } }}
      >
        <span style={{ fontSize: '14px', width: '18px', textAlign: 'center', flexShrink: 0 }}>{icon}</span>
        {label}
        {badge !== undefined && badge > 0 && (
          <span style={{
            marginLeft: 'auto', fontSize: '10px', fontWeight: 700,
            padding: '2px 7px', borderRadius: '999px',
            background: isSix ? '#2A4A8A' : '#134D38',
            color: isSix ? '#4F8EF7' : '#34D399',
          }}>{badge}</span>
        )}
      </div>
    )
  }

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#0D0F17' }}>

      <aside style={{
        width: '224px', minWidth: '224px',
        background: '#13161F',
        borderRight: '1px solid #252836',
        display: 'flex', flexDirection: 'column',
        position: 'sticky', top: 0, height: '100vh',
        overflowY: 'auto',
      }}>

        {/* Logo  - centralizado, com imagem ENOVA, igual ao protÃ³tipo */}
        <div style={{
          flexDirection: 'column', alignItems: 'center',
          padding: '16px 12px 10px', gap: '8px',
          borderBottom: '1px solid #252836',
          display: 'flex',
        }}>
          <img src={ENOVA_LOGO} alt="💳" style={{ width: '72px', height: 'auto', objectFit: 'contain' }} />
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '13px', fontWeight: 600, color: '#E8EAF0', lineHeight: '1.3' }}>Controle Fiscal</div>
            <div style={{ fontSize: '10px', color: '#7B82A0' }}>Gestão de Notas Fiscais</div>
          </div>
        </div>

        {/* Dashboard */}
        <div style={{ padding: '12px 10px 4px' }}>
          <div style={{ fontSize: '10px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1.2px', color: '#4A5070', padding: '0 8px', marginBottom: '4px' }}>Dashboard</div>
          <NavItem path="/dashboard" icon="📊" label="Painel" />
        </div>

        <div style={{ height: '1px', background: '#252836', margin: '6px 14px' }} />

        {/* Geral */}
        <div style={{ padding: '4px 10px' }}>
          <div style={{ fontSize: '10px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1.2px', color: '#4A5070', padding: '0 8px', marginBottom: '4px' }}>Geral</div>
          <NavItem path="/inicio" icon="🏠" label="Início" />
          <NavItem path="/faturamentos" icon="📋" label="Faturamentos" badge={15} />
          <NavItem path="/impostos" icon="💳" label="Impostos Pagos" />
        </div>

        <div style={{ height: '1px', background: '#252836', margin: '6px 14px' }} />

{/* Fiscal */}
        <div style={{ padding: '4px 10px' }}>
          <div style={{ fontSize: '10px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1.2px', color: '#4A5070', padding: '0 8px', marginBottom: '4px' }}>Fiscal</div>
          <NavItem path="/contabilidade" icon="🧾" label="Contabilidade" cor="purple" />
        </div>
        <div style={{ height: '1px', background: '#252836', margin: '6px 14px' }} />

        {/* Configurações */}
        <div style={{ padding: '4px 10px' }}>
          <div style={{ fontSize: '10px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1.2px', color: '#4A5070', padding: '0 8px', marginBottom: '4px' }}>Configurações</div>
          <NavItem path="/xml" icon="📥" label="Importar XML" />
          <NavItem path="/relatorios" icon="📈" label="Relatórios" cor="purple" />
          <NavItem path="/usuarios" icon="👤" label="Usuários" />
          <NavItem path="/empresas" icon="🏢" label="Empresas" />
        </div>

        <div style={{ height: '1px', background: '#252836', margin: '6px 14px' }} />

        {/* Colaboradores */}
        <div style={{ padding: '4px 10px' }}>
          <div style={{ fontSize: '10px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1.2px', color: '#4A5070', padding: '0 8px', marginBottom: '4px' }}>Colaboradores</div>
          <NavItem path="/encargos" icon="👷" label="Encargos" />
        </div>

        {/* RodapÃ©: Auditoria + Configurações */}
        <div style={{ marginTop: 'auto', padding: '10px', borderTop: '1px solid #252836' }}>
          <NavItem path="/auditoria" icon="📝" label="Log de Auditoria" />
          <NavItem path="/configuracoes" icon="⚙️" label="Configurações" />
        </div>
      </aside>

      {/* MAIN */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>

        {/* TOPBAR */}
        <div style={{
          background: '#13161F', borderBottom: '1px solid #252836',
          padding: '0 28px', height: '56px',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          position: 'sticky', top: 0, zIndex: 50,
        }}>
          <div>
            <div style={{ fontSize: '15px', fontWeight: 600, color: '#E8EAF0' }}>{nomePagina}</div>
            <div style={{ fontSize: '11px', color: '#7B82A0', marginTop: '2px' }}>            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            {showNovaNF && (
              <button
                onClick={onNovaNF}
                style={{
                  display: 'inline-flex', alignItems: 'center', gap: '6px',
                  padding: '7px 13px', borderRadius: '6px',
                  background: isSix ? '#4F8EF7' : '#34D399',
                  color: '#0D0F17', fontFamily: 'inherit',
                  fontSize: '12px', fontWeight: 600, cursor: 'pointer', border: 'none',
                }}
              >
                + Nova NF
              </button>
            )}
            <div
              onClick={logout}
              title="Sair"
              style={{ cursor: 'pointer', color: '#7B82A0', padding: '4px', fontSize: '16px' }}
              onMouseEnter={e => (e.currentTarget as HTMLDivElement).style.color = '#F87171'}
              onMouseLeave={e => (e.currentTarget as HTMLDivElement).style.color = '#7B82A0'}
            ></div>
          </div>
        </div>

        {/* CONTENT */}
        <div style={{ padding: '22px 28px', flex: 1 }}>
          {children}
        </div>
      </div>
    </div>
  )
}
